export const 三台神符三 = (bi) => {
    const u = bi.u, k = 1.38;
    const X = (c) => (c - 2.9) * k;
    const Z = (r) => (r - 0.8) * k + 1.1;
    const 線 = (書, 寬 = 0.28) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.3) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.3) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    const 乙 = (x0, z0, w = 1.4, h = 1.7, 寬 = 0.28) => 線(p => p.M(X(x0), Z(z0))
        .C(X(x0 + w * 0.9), Z(z0 - 0.1), X(x0 + w), Z(z0 + h * 0.35), X(x0 + w * 0.45), Z(z0 + h * 0.5))
        .C(X(x0), Z(z0 + h * 0.65), X(x0 + 0.1), Z(z0 + h), X(x0 + w * 0.7), Z(z0 + h)), 寬);
    // ●左點首桿
    點(0.9, 0.9, 0.36);
    線(p => p.M(X(1.3), Z(0.95)).L(X(5.6), Z(0.88)), 0.32);
    // 聿書頭（亖八貫上豎・左緣乙鉤三）
    for (const z of [1.6, 2.3, 3.0, 3.7, 4.4, 5.1, 5.8, 6.5])
        線(p => p.M(X(0.95), Z(z)).L(X(5.35), Z(z - 0.04)), 0.28);
    線(p => p.M(X(3.9), Z(1.4)).L(X(3.88), Z(4.4)), 0.3);
    for (const z of [2.2, 4.0, 5.7])
        出(p => p.M(X(0.9), Z(z)).C(X(0.6), Z(z + 0.2), X(0.6), Z(z + 0.5), X(0.85), Z(z + 0.65)), 0.24);
    // 桁帶左鉤
    線(p => p.M(X(0.7), Z(7.6)).L(X(5.3), Z(7.55)), 0.3);
    線(p => p.M(X(0.75), Z(8.4)).L(X(5.25), Z(8.35)), 0.28);
    出(p => p.M(X(0.75), Z(7.65)).C(X(0.7), Z(8.1), X(0.68), Z(8.5), X(0.65), Z(8.9)), 0.28);
    // 短桁點曲
    線(p => p.M(X(1.5), Z(9.4)).L(X(4.6), Z(9.35)), 0.28);
    出(p => p.M(X(0.6), Z(9.8)).C(X(0.45), Z(10.1), X(0.5), Z(10.4), X(0.75), Z(10.5)), 0.26);
    // ∩拱（●騎右肩・雙●足・左右緣豎）
    線(p => p.M(X(1.5), Z(13.7))
        .C(X(1.45), Z(12.3), X(1.9), Z(11.5), X(2.6), Z(11.5))
        .C(X(3.2), Z(11.5), X(3.5), Z(12.2), X(3.45), Z(13.6)), 0.3);
    點(3.35, 11.05, 0.3);
    點(1.5, 13.9, 0.32);
    點(3.45, 13.8, 0.32);
    線(p => p.M(X(0.9), Z(11.0)).L(X(0.88), Z(14.5)), 0.28);
    線(p => p.M(X(5.2), Z(10.8)).L(X(5.18), Z(14.6)), 0.28);
    // 尸目帶
    線(p => p.M(X(0.8), Z(15.2)).L(X(5.4), Z(15.15)), 0.3);
    出(p => p.M(X(0.9), Z(15.23)).L(X(0.88), Z(18.4)), 0.28);
    線(p => p.M(X(1.5), Z(15.8)).L(X(1.5), Z(18.4)).L(X(5.2), Z(18.35))
        .L(X(5.2), Z(15.75)).L(X(1.45), Z(15.8)), 0.28);
    線(p => p.M(X(1.6), Z(16.7)).L(X(5.1), Z(16.66)), 0.26);
    線(p => p.M(X(1.6), Z(17.6)).L(X(5.1), Z(17.56)), 0.26);
    // 愿曲群（頂桁・小目・右与・底心三鉤）
    線(p => p.M(X(1.0), Z(19.0)).L(X(5.3), Z(18.95)), 0.3);
    線(p => p.M(X(1.6), Z(19.5)).L(X(1.6), Z(21.0)).L(X(3.2), Z(20.96))
        .L(X(3.2), Z(19.46)).L(X(1.55), Z(19.5)), 0.26);
    線(p => p.M(X(1.7), Z(20.25)).L(X(3.1), Z(20.22)), 0.24);
    乙(3.6, 19.6, 1.5, 1.5, 0.26);
    for (const x of [1.2, 2.5, 3.8])
        出(p => p.M(X(x), Z(21.5)).C(X(x - 0.15), Z(22.0), X(x + 0.1), Z(22.4), X(x + 0.55), Z(22.5)), 0.26);
    出(p => p.M(X(1.0), Z(22.75)).C(X(2.4), Z(22.95), X(3.9), Z(22.9), X(5.1), Z(22.7)), 0.28);
    // 大乙帶
    線(p => p.M(X(0.8), Z(23.4)).L(X(5.4), Z(23.35)), 0.3);
    乙(1.0, 23.8, 3.8, 1.4, 0.3);
    線(p => p.M(X(0.9), Z(25.8)).L(X(5.2), Z(25.75)), 0.28);
    // 亖目框
    線(p => p.M(X(0.8), Z(26.8)).L(X(5.3), Z(26.76)), 0.28);
    線(p => p.M(X(0.85), Z(27.6)).L(X(5.25), Z(27.56)), 0.28);
    線(p => p.M(X(1.2), Z(28.1)).L(X(1.2), Z(30.6)).L(X(5.1), Z(30.55))
        .L(X(5.1), Z(28.05)).L(X(1.15), Z(28.1)), 0.28);
    線(p => p.M(X(1.3), Z(29.0)).L(X(5.0), Z(28.96)), 0.26);
    線(p => p.M(X(1.3), Z(29.9)).L(X(5.0), Z(29.86)), 0.26);
    // 桁三左豎承己小曲
    for (const z of [31.2, 32.1, 33.0])
        線(p => p.M(X(0.8), Z(z)).L(X(5.3), Z(z - 0.04)), 0.28);
    線(p => p.M(X(1.0), Z(31.2)).L(X(0.98), Z(34.6)), 0.28);
    線(p => p.M(X(2.2), Z(33.5))
        .C(X(3.9), Z(33.45), X(4.1), Z(33.85), X(3.1), Z(33.95))
        .C(X(2.2), Z(34.05), X(2.3), Z(34.45), X(3.5), Z(34.5)), 0.26);
    // 与鉤對承底桁小乙
    乙(1.4, 35.2, 1.6, 1.6);
    乙(3.4, 35.3, 1.6, 1.6);
    線(p => p.M(X(1.0), Z(37.35)).L(X(5.2), Z(37.3)), 0.28);
    乙(2.0, 37.8, 1.6, 1.0, 0.26);
    // 咼皿曲群
    線(p => p.M(X(1.6), Z(39.4)).L(X(1.6), Z(41.4)).L(X(4.8), Z(41.35))
        .L(X(4.8), Z(39.35)).L(X(1.55), Z(39.4)), 0.28);
    乙(2.1, 39.8, 1.6, 1.2, 0.24);
    線(p => p.M(X(1.5), Z(41.9))
        .C(X(1.4), Z(42.7), X(1.9), Z(43.15), X(3.1), Z(43.1))
        .C(X(4.2), Z(43.05), X(4.8), Z(42.6), X(4.8), Z(42.0)), 0.28);
    乙(2.4, 43.5, 1.8, 1.3, 0.28);
    // 底垂（左點・木撇捺・長垂曲尾）
    點(0.8, 45.5, 0.22);
    出(p => p.M(X(3.0), Z(45.3)).L(X(2.98), Z(49.8))
        .C(X(2.96), Z(50.4), X(2.7), Z(50.9), X(2.2), Z(51.1)), 0.34);
    出(p => p.M(X(2.98), Z(46.6)).C(X(2.5), Z(47.3), X(2.1), Z(47.8), X(1.7), Z(48.1)), 0.28);
    出(p => p.M(X(3.02), Z(46.6)).C(X(3.5), Z(47.3), X(3.9), Z(47.8), X(4.3), Z(48.1)), 0.28);
};
